23	#include <rime/translation.h>
24	#include <rime/translator.h>
25	
26	namespace rime {
27	
28	class ConcreteEngine : public Engine {
29	 public:
30	  ConcreteEngine();
31	  virtual ~ConcreteEngine();
32	  virtual bool ProcessKey(const KeyEvent& key_event);
33	  virtual void ApplySchema(Schema* schema);
34	  virtual void CommitText(string text);
35	  virtual void Compose(Context* ctx);
36	
37	 protected:
38	  void InitializeComponents();
39	  void InitializeOptions();
40	  void CalculateSegmentation(Segmentation* segments);
41	  void TranslateSegments(Segmentation* segments);
42	  void FormatText(string* text);
43	  void OnCommit(Context* ctx);
44	  void OnSelect(Context* ctx);
45	  void OnContextUpdate(Context* ctx);
46	  void OnOptionUpdate(Context* ctx, const string& option);
47	  void OnPropertyUpdate(Context* ctx, const string& property);
48	
49	  vector<of<Processor>> processors_;
50	  vector<of<Segmentor>> segmentors_;
51	  vector<of<Translator>> translators_;
52	  vector<of<Filter>> filters_;
53	  vector<of<Formatter>> formatters_;
54	  vector<of<Processor>> post_processors_;
55	  an<Switcher> switcher_;
56	};
57	
58	// implementations
59	
60	Engine* Engine::Create() {
61	  return new ConcreteEngine;
62	}
63	
64	Engine::Engine() : schema_(new Schema), context_(new Context) {}
65	
66	Engine::~Engine() {
67	  context_.reset();
68	  schema_.reset();
69	}
70	
71	ConcreteEngine::ConcreteEngine() {
72	  LOG(INFO) << "starting engine.";
73	  // receive context notifications
74	  context_->commit_notifier().connect([this](Context* ctx) { OnCommit(ctx); });
75	  context_->select_notifier().connect([this](Context* ctx) { OnSelect(ctx); });
76	  context_->update_notifier().connect(
77	      [this](Context* ctx) { OnContextUpdate(ctx); });
78	  context_->option_update_notifier().connect(
79	      [this](Context* ctx, const string& option) {
80	        OnOptionUpdate(ctx, option);
81	      });
82	  context_->property_update_notifier().connect(
83	      [this](Context* ctx, const string& property) {
84	        OnPropertyUpdate(ctx, property);
85	      });
86	
87	  switcher_ = New<Switcher>(this);
88	  // saved options should be loaded only once per input session
89	  switcher_->RestoreSavedOptions();
90	
91	  InitializeComponents();
92	  InitializeOptions();
93	}
94	
95	ConcreteEngine::~ConcreteEngine() {
96	  LOG(INFO) << "engine disposed.";
97	}
98	
99	bool ConcreteEngine::ProcessKey(const KeyEvent& key_event) {
100	  DLOG(INFO) << "process key: " << key_event;
101	  ProcessResult ret = kNoop;
102	  for (auto& processor : processors_) {
103	    ret = processor->ProcessKeyEvent(key_event);
104	    if (ret == kRejected)
105	      break;
106	    if (ret == kAccepted)
107	      return true;
108	  }
109	  // record unhandled keys, eg. spaces, numbers, bksp's.
110	  context_->commit_history().Push(key_event);
111	  // post-processing
112	  for (auto& processor : post_processors_) {
113	    ret = processor->ProcessKeyEvent(key_event);
114	    if (ret == kRejected)
115	      break;
116	    if (ret == kAccepted)
117	      return true;
118	  }
119	  // notify interested parties
120	  context_->unhandled_key_notifier()(context_.get(), key_event);
121	  return false;
122	}
123	
124	void ConcreteEngine::OnContextUpdate(Context* ctx) {
125	  if (!ctx)
126	    return;
127	  Compose(ctx);
128	}
129	
130	void ConcreteEngine::OnOptionUpdate(Context* ctx, const string& option) {
131	  if (!ctx)
132	    return;
133	  LOG(INFO) << "updated option: " << option;
134	  // apply new option to active segment
135	  if (ctx->IsComposing()) {
136	    ctx->RefreshNonConfirmedComposition();
137	  }
138	  // notification
139	  bool option_is_on = ctx->get_option(option);
140	  string msg(option_is_on ? option : "!" + option);
141	  message_sink_("option", msg);
142	}
143	
144	void ConcreteEngine::OnPropertyUpdate(Context* ctx, const string& property) {
145	  if (!ctx)
146	    return;
147	  LOG(INFO) << "updated property: " << property;
148	  // notification
149	  string value = ctx->get_property(property);
150	  string msg(property + "=" + value);
151	  message_sink_("property", msg);
152	}
153	
154	void ConcreteEngine::Compose(Context* ctx) {
155	  if (!ctx)
156	    return;
157	  Composition& comp = ctx->composition();
158	  const string active_input = ctx->input().substr(0, ctx->caret_pos());
159	  DLOG(INFO) << "active input: " << active_input;
160	  comp.Reset(active_input);
161	  if (ctx->caret_pos() < ctx->input().length() &&
162	      ctx->caret_pos() == comp.GetConfirmedPosition()) {
163	    // translate one segment past caret pos.
164	    comp.Reset(ctx->input());
165	  }
166	  CalculateSegmentation(&comp);
167	  TranslateSegments(&comp);
168	  DLOG(INFO) << "composition: [" << comp.GetDebugText() << "]";
169	}
170	
171	void ConcreteEngine::CalculateSegmentation(Segmentation* segments) {
172	  DLOG(INFO) << "CalculateSegmentation, segments: " << segments->size()
173	             << ", finished? " << segments->HasFinishedSegmentation();
174	  while (!segments->HasFinishedSegmentation()) {
175	    size_t start_pos = segments->GetCurrentStartPosition();
176	    size_t end_pos = segments->GetCurrentEndPosition();
177	    DLOG(INFO) << "start pos: " << start_pos;
178	    DLOG(INFO) << "end pos: " << end_pos;
179	    // recognize a segment by calling the segmentors in turn
180	    for (auto& segmentor : segmentors_) {
181	      if (!segmentor->Proceed(segments))
182	        break;
183	    }
184	    DLOG(INFO) << "segmentation: " << *segments;
185	    // no advancement
186	    if (start_pos == segments->GetCurrentEndPosition())
187	      break;
188	    // only one segment is allowed past caret pos, which is the segment
189	    // immediately after the caret.
190	    if (start_pos >= context_->caret_pos())
191	      break;
192	    // move onto the next segment...
193	    if (!segments->HasFinishedSegmentation())
194	      segments->Forward();
195	  }
196	  // start an empty segment only at the end of a confirmed composition.
197	  if (!segments->empty() && !segments->back().HasTag("placeholder"))
198	    segments->Trim();
199	  if (!segments->empty() && segments->back().status >= Segment::kSelected)
200	    segments->Forward();
201	}
202	
203	void ConcreteEngine::TranslateSegments(Segmentation* segments) {
204	  DLOG(INFO) << "TranslateSegments: " << *segments;
205	  for (Segment& segment : *segments) {
206	    DLOG(INFO) << "segment [" << segment.start << ", " << segment.end
207	               << "), status: " << segment.status;
208	    if (segment.status >= Segment::kGuess)
209	      continue;
210	    size_t len = segment.end - segment.start;
211	    string input = segments->input().substr(segment.start, len);
212	    DLOG(INFO) << "translating segment: [" << input << "]";
213	    auto menu = New<Menu>();
214	    for (auto& translator : translators_) {
215	      auto translation = translator->Query(input, segment);
216	      if (!translation)
217	        continue;
218	      if (translation->exhausted()) {
219	        DLOG(INFO) << translator->name_space() << " made a futile translation.";
220	        continue;
221	      }
222	      menu->AddTranslation(translation);
223	    }
224	    for (auto& filter : filters_) {
225	      if (filter->AppliesToSegment(&segment)) {
226	        menu->AddFilter(filter.get());
227	      }
228	    }
229	    segment.status = Segment::kGuess;
230	    segment.menu = menu;
231	    segment.selected_index = 0;
232	  }
233	}
234	
235	void ConcreteEngine::FormatText(string* text) {
236	  if (formatters_.empty())
237	    return;
238	  DLOG(INFO) << "applying formatters.";
239	  for (auto& formatter : formatters_) {
240	    formatter->Format(text);
241	  }
242	}
243	
244	void ConcreteEngine::CommitText(string text) {
245	  context_->commit_history().Push(CommitRecord{"raw", text});
246	  FormatText(&text);
247	  DLOG(INFO) << "committing text: " << text;
248	  sink_(text);
249	}
250	
251	void ConcreteEngine::OnCommit(Context* ctx) {
252	  context_->commit_history().Push(ctx->composition(), ctx->input());
253	  string text = ctx->GetCommitText();
254	  FormatText(&text);
255	  DLOG(INFO) << "committing composition: " << text;
256	  sink_(text);
257	}
258	
259	void ConcreteEngine::OnSelect(Context* ctx) {
260	  Segment& seg(ctx->composition().back());
261	  seg.Close();
262	  if (seg.end == ctx->input().length()) {
263	    // composition has finished
264	    seg.status = Segment::kConfirmed;
265	    // strategy one: commit directly;
266	    // strategy two: continue composing with another empty segment.
267	    if (ctx->get_option("_auto_commit"))
268	      ctx->Commit();
269	    else
270	      ctx->composition().Forward();
271	  } else {
272	    bool reached_caret_pos = (seg.end >= ctx->caret_pos());
273	    ctx->composition().Forward();
274	    if (reached_caret_pos) {
275	      // finished converting current segment
276	      // move caret to the end of input
277	      ctx->set_caret_pos(ctx->input().length());
278	    } else {
279	      Compose(ctx);
280	    }
281	  }
282	}
283	
284	void ConcreteEngine::ApplySchema(Schema* schema) {
285	  if (!schema)
286	    return;
287	  schema_.reset(schema);
288	  context_->Clear();
289	  context_->ClearTransientOptions();
290	  InitializeComponents();
291	  InitializeOptions();
292	  switcher_->SetActiveSchema(schema_->schema_id());
293	  message_sink_("schema", schema_->schema_id() + "/" + schema_->schema_name());
294	}
295	
296	// Helper template function to create components
297	template <typename T>
298	inline void CreateComponentsFromList(Engine* engine,
299	                                     Config* config,
300	                                     const string& config_key,
301	                                     const string& component_type,
302	                                     vector<an<T>>& target_collection) {
303	  if (auto component_list = config->GetList(config_key)) {
304	    size_t n = component_list->size();
305	    for (size_t i = 0; i < n; ++i) {
306	      auto prescription = As<ConfigValue>(component_list->GetAt(i));
307	      if (!prescription)
308	        continue;
309	      Ticket ticket{engine, component_type, prescription->str()};
310	      auto c = T::Require(ticket.klass);
311	      if (!c) {
312	        LOG(ERROR) << "error creating " << component_type << ": '"
313	                   << ticket.klass << "'";
314	        continue;
315	      }
316	      auto component = c->Create(ticket);
317	      if (!component) {
318	        LOG(ERROR) << "error creating " << component_type << " from ticket: '"
319	                   << ticket.klass << "'";
320	        continue;
321	      }
322	      an<T> instance(component);
323	      target_collection.push_back(instance);
324	    }
325	  }
326	}
327	
328	void ConcreteEngine::InitializeComponents() {
329	  processors_.clear();
330	  segmentors_.clear();
331	  translators_.clear();
332	  filters_.clear();
333	  formatters_.clear();
334	  post_processors_.clear();
335	
336	  if (switcher_) {
337	    processors_.push_back(switcher_);
338	    if (schema_->schema_id() == ".default") {
339	      if (Schema* schema = switcher_->CreateSchema()) {
340	        schema_.reset(schema);
341	      }
342	    }
343	  }
344	
345	  Config* config = schema_->config();
346	  if (!config)
347	    return;
348	
349	  // Create components using inline template function
350	  CreateComponentsFromList<Processor>(this, config, "engine/processors",
351	                                      "processor", processors_);
352	  CreateComponentsFromList<Segmentor>(this, config, "engine/segmentors",
353	                                      "segmentor", segmentors_);
354	  CreateComponentsFromList<Translator>(this, config, "engine/translators",
355	                                       "translator", translators_);
356	  CreateComponentsFromList<Filter>(this, config, "engine/filters", "filter",
357	                                   filters_);
358	  // create formatters
359	  auto c_formatter = Formatter::Require("shape_formatter");
360	  if (c_formatter) {
361	    an<Formatter> f(c_formatter->Create(Ticket(this)));
